-- keys:
-- KEYS[1] = countsHashKey
-- KEYS[2] = weightsHashKey   (可与 counts 合并成一个 key，但分开更通用)
-- returns: 0 if no stock, else prizeId (as number)

local counts = redis.call('HGETALL', KEYS[1])
if #counts == 0 then
    return 0
end

-- build table of items
local items = {}
local total = 0
for i = 1, #counts, 2 do
    local pid = counts[i]
    local cnt = tonumber(counts[i+1])
    if cnt and cnt > 0 then
        local w = tonumber(redis.call('HGET', KEYS[2], pid)) or 1
        local contrib = cnt * w
        if contrib > 0 then
            table.insert(items, {pid=pid, cnt=cnt, w=w, contrib=contrib})
            total = total + contrib
        end
    end
end

if total == 0 then
    return 0
end

-- seed random with time for better randomness in Redis Lua
local t = redis.call('TIME')
math.randomseed(tonumber(t[2]) + tonumber(t[1]))

local r = math.random(1, total)
local acc = 0
for i, it in ipairs(items) do
    acc = acc + it.contrib
    if r <= acc then
        -- decrement count
        redis.call('HINCRBY', KEYS[1], it.pid, -1)
        local newc = tonumber(redis.call('HGET', KEYS[1], it.pid)) or 0
        if newc <= 0 then
            redis.call('HDEL', KEYS[1], it.pid)
            -- optional: also HDEL weights entry if weights stored per-pool
            -- redis.call('HDEL', KEYS[2], it.pid)
        end
        return tonumber(it.pid)
    end
end

return 0
